  1→/**
  2→ * Workspace-related TypeScript type definitions
  3→ * Centralized types for workspace entities and operations
  4→ */
  5→
  6→import type { SessionStatus } from "./session";
  7→
  8→// Canonical enum types — defined as Zod schemas in shared/enums.ts,
  9→// imported here for local use and re-exported for backwards compat.
 10→import type { WorkspaceState, SetupStatus, WorkspaceStatus } from "../enums";
 11→export type { WorkspaceState, SetupStatus, WorkspaceStatus };
 12→
 13→/**
 14→ * Core workspace entity
 15→ * Represents a git worktree-based development workspace
 16→ */
 17→export interface Workspace {
 18→  id: string;
 19→  repository_id: string;
 20→  slug: string;
 21→  title: string | null;
 22→  git_branch: string | null;
 23→  git_target_branch: string | null;
 24→  state: WorkspaceState;
 25→  status: WorkspaceStatus;
 26→  current_session_id: string | null;
 27→  session_status: SessionStatus | null;
 28→  model: string | null;
 29→  session_error_category: string | null;
 30→  session_error_message: string | null;
 31→  latest_message_sent_at: string | null;
 32→  updated_at: string;
 33→  repo_name: string;
 34→  root_path: string;
 35→  /** Computed filesystem path to the workspace directory */
 36→  workspace_path: string;
 37→  git_default_branch?: string;
 38→  setup_status: SetupStatus;
 39→  init_stage?: string | null;
 40→  error_message: string | null;
 41→  pr_url?: string | null;
 42→  pr_number?: number | null;
 43→  archive_commit?: string | null;
 44→  archived_at?: string | null;
 45→}
 46→
 47→/**
 48→ * Repository grouping for sidebar display
 49→ * Groups workspaces by their parent repository
 50→ */
 51→export interface RepoGroup {
 52→  repo_id: string;
 53→  repo_name: string;
 54→  sort_order: number;
 55→  git_origin_url?: string | null;
 56→  workspaces: Workspace[];
 57→}
 58→
 59→/**
 60→ * Git diff statistics for a workspace
 61→ * Shows additions and deletions relative to main branch
 62→ */
 63→export interface DiffStats {
 64→  additions: number;
 65→  deletions: number;
 66→}
 67→
 68→/**
 69→ * File-level change information
 70→ * Individual file modifications with line counts
 71→ */
 72→export interface FileChange {
 73→  file: string;
 74→  file_path?: string; // Some APIs use file_path instead
 75→  additions: number;
 76→  deletions: number;
 77→  /** true = committed (in HEAD), false = uncommitted (working dir only), undefined = unknown */
 78→  committed?: boolean;
 79→}
 80→
 81→/**
 82→ * File edit details from Claude Code actions
 83→ * Tracks Edit and Write tool usage per file
 84→ */
 85→export interface FileEdit {
 86→  old_string?: string;
 87→  new_string?: string;
 88→  content?: string;
 89→  timestamp: string;
 90→  message_id: string;
 91→  tool_name: "Edit" | "Write";
 92→}
 93→
 94→/**
 95→ * Grouped file changes with edit history
 96→ * Aggregates all edits for a specific file
 97→ */
 98→export interface FileChangeGroup {
 99→  file_path: string;
100→  edits: FileEdit[];
101→  first_timestamp: string;
102→  last_timestamp: string;
103→}
104→
105→/**
106→ * Full file diff content from git
107→ * Includes raw diff text and old/new file contents for side-by-side view
108→ */
109→export interface FileDiff {
110→  file: string;
111→  diff: string;
112→  old_content: string | null;
113→  new_content: string | null;
114→}
115→
116→/**
117→ * Result from listing changed files with truncation info
118→ */
119→export interface ChangedFilesResult {
120→  files: FileChange[];
121→  truncated: boolean;
122→  total_count: number;
123→}
124→
125→/**
126→ * Git branch information
127→ */
128→export interface BranchInfo {
129→  name: string;
130→  is_remote: boolean;
131→  is_head: boolean;
132→}
