 48→app.get("/workspaces/by-repo", (c) => {
 49→  const db = getDatabase();
 50→  const stateParam = c.req.query("state");
 51→  const workspaces = getWorkspacesByRepo(db, stateParam);
 52→
 53→  const grouped: Record<string, any> = {};
 54→  workspaces.forEach((workspace) => {
 55→    const repoId = workspace.repository_id || "unknown";
 56→    if (!grouped[repoId]) {
 57→      grouped[repoId] = {
 58→        repo_id: repoId,
 59→        repo_name: workspace.repo_name || "Unknown",
 60→        sort_order: workspace.repo_sort_order || 999,
 61→        git_origin_url: workspace.git_origin_url ?? null,
 62→        workspaces: [],
 63→      };
 64→    }
 65→    grouped[repoId].workspaces.push({
 66→      ...workspace,
 67→      workspace_path: computeWorkspacePath(workspace),
 68→    });
 69→  });
 70→
 71→  // Backfill repos that have no matching workspaces (e.g. all archived)
 72→  // so they still appear in the sidebar.
 73→  const allRepos = getAllRepositorySummaries(db);
 74→  for (const repo of allRepos) {
 75→    if (!grouped[repo.id]) {
 76→      grouped[repo.id] = {
 77→        repo_id: repo.id,
 78→        repo_name: repo.name,
 79→        sort_order: repo.sort_order ?? 999,
 80→        git_origin_url: repo.git_origin_url ?? null,
 81→        workspaces: [],
 82→      };
 83→    }
 84→  }
 85→
 86→  const result = Object.values(grouped).sort((a: any, b: any) => a.sort_order - b.sort_order);
 87→  return c.json(result);
 88→});
