 97→app.patch("/workspaces/:id", async (c) => {
 98→  const db = getDatabase();
 99→  const id = c.req.param("id");
100→  const { state, status } = parseBody(PatchWorkspaceBody, await c.req.json());
101→
102→  if (status) {
103→    setWorkspaceStatus(id, status);
104→  }
105→
106→  if (state) {
107→    db.prepare("UPDATE workspaces SET state = ? WHERE id = ?").run(state, id);
108→
109→    if (state === "archived") {
110→      autoProgressStatus(id, "done", { force: true });
111→
112→      // Run archive lifecycle hook (best-effort)
113→      try {
114→        const ws = getWorkspaceById(db, id);
115→        if (ws && ws.root_path) {
116→          const wsPath = computeWorkspacePath(ws);
117→          const manifest = readManifestWithFallback(wsPath, ws.root_path);
118→          const archiveCmd = manifest ? getArchiveCommand(manifest) : null;
119→          if (archiveCmd) {
120→            const archiveEnv = getDeusEnv(manifest!, {
121→              id: ws.id,
122→              rootPath: ws.root_path,
123→              workspacePath: wsPath,
124→            });
125→            const archiveProc = spawn("sh", ["-c", archiveCmd], {
126→              cwd: wsPath,
127→              env: { ...process.env, ...archiveEnv },
128→              stdio: "ignore",
129→              detached: false,
130→            });
131→            archiveProc.on("error", (err) => {
132→              console.error(`Archive hook error for workspace ${id}:`, err.message);
133→            });
134→            archiveProc.unref();
135→          }
136→        }
137→      } catch (err) {
138→        console.warn("[WORKSPACE] Archive lifecycle hook failed (continuing):", err);
139→      }
140→    }
141→
142→    // Unarchive: restore done → in-progress
143→    if (state === "ready") {
144→      const ws = getWorkspaceRaw(db, id);
145→      if (ws?.status === "done") {
146→        autoProgressStatus(id, "in-progress", { force: true });
147→      }
148→    }
149→  }
150→  const updated = getWorkspaceRaw(db, id);

150→  const updated = getWorkspaceRaw(db, id);
151→  invalidate(["workspaces", "sessions", "stats"]);
152→  return c.json(updated);
153→});
