155→// Create workspace
156→app.post("/workspaces", async (c) => {
157→  const db = getDatabase();
158→  const { repository_id, source_branch, pr_number, pr_url, pr_title, target_branch } = parseBody(
159→    CreateWorkspaceBody,
160→    await c.req.json()
161→  );
162→
163→  const repo = getRepositoryById(db, repository_id);
164→  if (!repo) throw new NotFoundError("Repository not found");
165→
166→  const workspace_name = generateUniqueName(db);
167→  const parent_branch = source_branch || repo.git_default_branch || "main";
168→  const workspaceId = uuidv7();
169→
170→  let branchPrefix = "workspace";
171→  try {
172→    const gitUser = execSync("git config user.name", { cwd: repo.root_path!, encoding: "utf8" })
173→      .trim()
174→      .toLowerCase()
175→      .replace(/[^a-z0-9_-]/g, "-");
176→    if (gitUser) branchPrefix = gitUser;
177→  } catch {}
178→  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
179→
180→  // ─── IMPORTANT: Remote-first branch strategy ───────────────────────
181→  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
182→  // local <parent_branch>. Diffs are computed against origin/<branch>
183→  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
184→  // is stale, the merge-base drifts and every file since the divergence
185→  // shows as "changed" — producing hundreds of phantom file changes.
186→  //
187→  // Fetch the remote branch before creating the worktree so that:
188→  // 1. The worktree starts from the latest upstream commit
189→  // 2. Diff merge-base matches what we branched from (zero phantom changes)
190→  // 3. PRs will be clean against the upstream target
191→  //
192→  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
193→  // creation is already async (worktree add runs in a child process) and
194→  // correctness matters more here.
195→  // ───────────────────────────────────────────────────────────────────
196→  try {
197→    await execFileAsync("git", ["fetch", "origin", parent_branch], {
198→      cwd: repo.root_path!,
199→      timeout: 15000,
200→    });
201→  } catch (fetchErr) {
202→    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
203→    // whatever local state we have. The worktree will still be created
204→    // from the local branch — diffs might be off but it's better than
205→    // blocking workspace creation entirely.
206→    console.warn(
207→      `[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`,
208→      fetchErr
209→    );
210→  }
211→
212→  db.prepare(
213→    `
214→    INSERT INTO workspaces (
215→      id, repository_id, slug, title, git_branch,
216→      git_target_branch, pr_url, pr_number, state, updated_at
217→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'))
218→  `
219→  ).run(
220→    workspaceId,
221→    repository_id,
222→    workspace_name,
223→    pr_title || null,
224→    placeholderBranchName,
225→    target_branch || repo.git_default_branch || "main",
226→    pr_url || null,
227→    pr_number || null,
228→    "initializing"
229→  );
230→
231→  // Branch from origin/<parent_branch> when available (fetched above).
232→  // Falls back to local <parent_branch> if remote doesn't exist.
233→  const worktreeBase = await (async () => {
234→    try {
235→      await execFileAsync(
236→        "git",
237→        ["show-ref", "--verify", "--quiet", `refs/remotes/origin/${parent_branch}`],
238→        {
239→          cwd: repo.root_path!,
240→          timeout: 2000,
241→        }
242→      );
243→      return `origin/${parent_branch}`;
244→    } catch {
245→      return parent_branch;
246→    }
247→  })();
248→
249→  const workspacePath = path.join(repo.root_path!, ".deus", workspace_name);
250→
251→  // Fire-and-forget: run the init pipeline async (don't await).
252→  // Pipeline handles: worktree creation → deps install → .env copy → session creation.
253→  // Progress events flow: stdout → Electron main process → IPC events → Frontend.
254→  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
255→  initializeWorkspace({
256→    workspaceId,
257→    repositoryId: repository_id,
258→    repoRootPath: repo.root_path!,
259→    workspacePath,
260→    branchName: placeholderBranchName,
261→    worktreeBase,
262→    parentBranch: parent_branch,
263→  })
264→    .then(() => {
265→      // Workspace is ready — check for manifest setup script
266→      const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
267→      const setupCmd = manifest ? getSetupCommand(manifest) : null;
268→      if (setupCmd && manifest) {
269→        db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
270→        const setupEnv = getDeusEnv(manifest, {
271→          id: workspaceId,
272→          rootPath: repo.root_path!,
273→          workspacePath,
274→        });
275→        runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
276→      }
277→    })
278→    .catch((err) => {
279→      // Belt-and-suspenders: initializeWorkspace handles its own errors,
280→      // but if something truly unexpected escapes, don't leave workspace stuck.
281→      console.error("[WORKSPACE] Unhandled init pipeline error:", err);
282→      try {
283→        db.prepare(
284→          "UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'"
285→        ).run(workspaceId);
286→        invalidate(["workspaces", "stats"]);
287→      } catch {}
288→    });
289→
290→  const workspace = getWorkspaceForMiddleware(db, workspaceId);
291→  if (!workspace) throw new NotFoundError("Workspace not found after creation");
292→
293→  // Push immediately so clients see the workspace in 'initializing' state.
294→  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
295→  // The init pipeline will invalidate again when it transitions to 'ready'.
296→  invalidate(["workspaces", "stats"]);
297→
298→  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
299→});
