301→// List all sessions for a workspace (used by chat tab reconstruction)
302→app.get("/workspaces/:id/sessions", (c) => {
303→  const db = getDatabase();
304→  const workspaceId = c.req.param("id");
305→  const workspace = getWorkspaceRaw(db, workspaceId);
306→  if (!workspace) throw new NotFoundError("Workspace not found");
307→  const sessions = getSessionsByWorkspaceId(db, workspaceId);
308→  return c.json(sessions);
309→});
