311→// Create a new session for an existing workspace
312→app.post("/workspaces/:id/sessions", (c) => {
313→  const db = getDatabase();
314→  const workspaceId = c.req.param("id");
315→
316→  const workspace = getWorkspaceRaw(db, workspaceId);
317→  if (!workspace) throw new NotFoundError("Workspace not found");
318→
319→  const sessionId = uuidv7();
320→
321→  const createSession = db.transaction(() => {
322→    db.prepare(
323→      "INSERT INTO sessions (id, workspace_id, status, updated_at) VALUES (?, ?, 'idle', datetime('now'))"
324→    ).run(sessionId, workspaceId);
325→
326→    db.prepare(
327→      "UPDATE workspaces SET current_session_id = ?, updated_at = datetime('now') WHERE id = ?"
328→    ).run(sessionId, workspaceId);
329→  });
330→
331→  createSession();
332→  invalidate(["workspaces", "sessions", "stats"]);
333→
334→  const session = getSessionRaw(db, sessionId);
335→  return c.json(session);
336→});
