339→
340→// Get parsed manifest + normalized tasks for a workspace
341→app.get("/workspaces/:id/manifest", withWorkspace, (c) => {
342→  const workspace = c.get("workspace");
343→  const workspacePath = c.get("workspacePath");
344→  if (!workspace.root_path) {
345→    return c.json({ manifest: null, tasks: [] });
346→  }
347→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
348→  if (!manifest) return c.json({ manifest: null, tasks: [] });
349→  const tasks = getNormalizedTasks(manifest);

