451→                          type="text"
452→                          value={repoFilter}
453→                          onChange={(e) => setRepoFilter(e.target.value)}
454→                          placeholder="Search repos..."
455→                          className="text-text-primary placeholder:text-text-disabled w-full bg-transparent text-xs outline-none"
456→                        />
457→                      </div>
458→
459→                      {/* Repo list — virtualized scroll for 30+ repos */}
460→                      <div className="scrollbar-vibrancy max-h-[224px] overflow-y-auto py-1">
461→                        {filteredRepos.length === 0 && (
462→                          <div className="text-text-disabled px-3 py-3 text-center text-xs">
463→                            No repos match
