465→                        )}
466→                        {filteredRepos.map((repo) => {
467→                          const isSelected = repo.id === selectedRepoId;
468→                          return (
469→                            <button
470→                              key={repo.id}
471→                              type="button"
472→                              onClick={() => handleSelectRepo(repo.id)}
473→                              className={cn(
474→                                "flex w-full items-center justify-between px-3 py-1.5 text-left text-xs transition-colors duration-100",
475→                                "hover:bg-bg-raised/45",
476→                                isSelected ? "text-text-primary" : "text-text-secondary"
477→                              )}
478→                            >
479→                              <div className="flex items-center gap-2 overflow-hidden">
480→                                {isSelected ? (
481→                                  <span className="relative flex h-1 w-1 shrink-0" aria-hidden>
482→                                    <span className="absolute -inset-px rounded-full bg-emerald-400/25 blur-[1.5px]" />
483→                                    <span className="relative h-1 w-1 rounded-full bg-emerald-400" />
484→                                  </span>
485→                                ) : (
486→                                  <span className="h-1.5 w-1.5 shrink-0" />
