496→                                )}
497→                              </div>
498→                            </button>
499→                          );
500→                        })}
501→                      </div>
502→
503→                      {/* Add repo actions */}
504→                      <div className="border-border-subtle border-t py-1">
505→                        {capabilities.nativeFolderPicker && onOpenProject && (
506→                          <button
507→                            type="button"
508→                            onClick={() => {
509→                              setRepoPickerOpen(false);
510→                              onOpenProject();
511→                            }}
512→                            className="text-text-muted hover:text-text-secondary hover:bg-bg-raised/45 flex w-full items-center gap-2 px-3 py-1.5 text-xs transition-colors duration-100"
513→                          >
514→                            <FolderOpen className="size-3 shrink-0" />
515→                            <span>Open local...</span>
516→                          </button>
