525→                            className="text-text-muted hover:text-text-secondary hover:bg-bg-raised/45 flex w-full items-center gap-2 px-3 py-1.5 text-xs transition-colors duration-100"
526→                          >
527→                            <GitBranch className="size-3 shrink-0" />
528→                            <span>Clone from GitHub</span>
529→                          </button>
530→                        )}
531→                      </div>
532→                    </motion.div>
533→                  )}
534→                </AnimatePresence>
535→              </div>
536→            ) : (
537→              /* Zero repos — "Add a project" label */
538→              <span className="text-text-muted flex items-center gap-1.5 px-2.5 py-1.5 text-xs">
539→                <FolderOpen className="size-3" />
540→                <span className="font-medium">Add a project</span>
541→              </span>
542→            )}
543→
544→            {/* Branch picker (right side) — only when repos exist */}
545→            {hasRepos && (
546→              <BranchSelector
547→                repoId={selectedRepoId}
