605→            rows={3}
606→            className={cn(
607→              "text-text-primary placeholder:text-text-disabled w-full resize-none bg-transparent px-4 pt-3 pb-1 text-sm leading-relaxed outline-none",
608→              "scrollbar-vibrancy min-h-[76px] max-h-48 overflow-y-auto",
609→              !hasRepos && "pointer-events-none opacity-40"
610→            )}
611→          />
