  7→
  8→import { useMemo, useCallback, useEffect, useRef } from "react";
  9→import type { Dispatch, SetStateAction } from "react";
 10→import { SessionPanel } from "@/features/session";
 11→import type { SessionPanelRef } from "@/features/session";
 12→import { useWorkingSessionIds } from "@/features/session/api/session.queries";
 13→import { useUnreadStore, unreadActions } from "@/features/session/store/unreadStore";
 14→import { WorkspaceEmptyState } from "@/features/session/ui/WorkspaceEmptyState";
 15→import { MainContentTabBar } from "@/features/workspace";
