467→      {settingsOpen ? (
468→        <SettingsSidebar />
469→      ) : loading ? (
470→        <SidebarSkeleton />
471→      ) : (
472→        <AppSidebar
473→          repositories={repoGroups}
474→          selectedWorkspaceId={selectedWorkspace?.id || null}
475→          diffStatsMap={bulkDiffStatsQuery.data}
476→          onWorkspaceClick={handleWorkspaceClick}
477→          onNewWorkspace={repoActions.handleNewWorkspace}
478→          onNewWorkspaceFromGitHub={setGithubPickerRepoId}
479→          onAddRepository={repoActions.handleOpenProject}
480→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
481→          onArchive={archiveWorkspace}
482→          onStatusChange={handleStatusChange}
483→          onNewSession={() => selectWorkspace(null)}
