485→        />
486→      )}
487→
488→      {/* Sidebar resize handle */}
489→      <SidebarResizeHandle onSizeChange={setSidebarWidth} onDraggingChange={setSidebarDragging} />
490→
491→      {/* Main Content — swap between app content and settings page */}
492→      {settingsOpen ? (
493→        <SettingsPage />
494→      ) : (
495→        <MainContent
496→          selectedWorkspace={selectedWorkspace}
497→          prStatus={prStatusQuery.data ?? null}
498→          ghStatus={ghStatusQuery.data}
499→          workspaceChatPanelRef={workspaceChatPanelRef}
500→          onCreateWorkspace={openNewWorkspaceModal}
501→          onOpenProject={repoActions.handleOpenProject}
502→          onCloneRepository={() => repoActions.setShowCloneModal(true)}
503→          repos={repos}
504→          onSendFromWelcome={handleSendFromWelcome}
