 18→ */
 19→
 20→import { useRef, useCallback, useMemo, useEffect } from "react";
 21→import type { ImperativePanelHandle } from "react-resizable-panels";
 22→import type { SessionPanelRef } from "@/features/session";
 23→import { WelcomeView } from "@/features/repository";
 24→import { useWorkspaceLayout } from "@/features/workspace";
 25→import { useCollapsedSizePercent } from "@/features/workspace/hooks/useCollapsedSizePercent";
 26→import type { ContentTab } from "@/features/workspace/store";
 27→import { useFileWatcher } from "@/features/file-browser/hooks/useFileWatcher";
 28→import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
 29→import { ContentTabBar } from "./ContentTabBar";
 30→import { isTabVisible } from "./content-tabs";
 31→import { PRActions } from "@/features/workspace/ui/PRActions";
 32→import { useSettings } from "@/features/settings/api/settings.queries";
 33→import { SidebarInset, useSidebar } from "@/components/ui";
 34→import { cn } from "@/shared/lib/utils";
 35→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 36→import { PanelLeft } from "lucide-react";
 37→import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
 38→import { useUpdateWorkspaceStatus } from "@/features/workspace/api";
 39→import { REVIEW_CODE } from "@/features/session/lib/sessionPrompts";
 40→import { native } from "@/platform";
 41→import { BROWSER_WORKSPACE_CHANGE } from "@shared/events";
 42→import { useBrowserWindowStore } from "@/features/browser/store";
 43→import { track } from "@/platform/analytics";
 44→import { ConnectionBanner, useConnectionState } from "@/features/connection";
 45→import { useIsMobile } from "@/shared/hooks/use-mobile";
 46→import { ChatArea } from "./ChatArea";
 47→import { ContentView } from "./ContentView";
 48→import { MobileLayout } from "./MobileLayout";
 49→import { CollapsedChatStrip, CollapsedContentStrip } from "./CollapsedPanelStrips";
 50→import { useWorkspaceActions } from "./hooks/useWorkspaceActions";
 51→import { usePanelShortcuts } from "./hooks/usePanelShortcuts";
 52→
 53→interface MainContentProps {
 54→  selectedWorkspace: Workspace | null;
 55→  prStatus: PRStatus | null;
 56→  ghStatus?: GhCliStatus | null;
 57→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 58→  onCreateWorkspace: () => void;
 59→  onOpenProject: () => void;
 60→  onCloneRepository: () => void;
 61→  /** Repos for the welcome screen's repo picker */
 62→  repos: import("@/features/repository/types").Repository[];
 63→  /** Handler for sending the first message from the welcome screen.
 64→   *  Creates workspace + selects it + queues the first message. */
 65→  onSendFromWelcome: (repoId: string, message: string, model: string) => void;
 66→  /** True while the welcome-screen send is creating a workspace */
 67→  welcomeSending?: boolean;
 68→}
 69→
 70→export function MainContent({
 71→  selectedWorkspace,
 72→  prStatus,
 73→  ghStatus,
 74→  workspaceChatPanelRef,
 75→  onCreateWorkspace,
 76→  onOpenProject,
 77→  onCloneRepository,
 78→  repos,
 79→  onSendFromWelcome,
 80→  welcomeSending,
 81→}: MainContentProps) {
 82→  const { open: sidebarOpen, toggleSidebar } = useSidebar();
 83→  const isMobile = useIsMobile();
 84→
 85→  const selectedWorkspaceId = selectedWorkspace?.id ?? null;
 86→  const {
 87→    contentTab,
 88→    setContentTab,
 89→    chatPanelCollapsed,
 90→    setChatPanelCollapsed,
 91→    contentPanelCollapsed,
 92→    setContentPanelCollapsed,
 93→  } = useWorkspaceLayout(selectedWorkspaceId);
 94→
 95→  // Effective tab: if the stored tab is hidden by experimental settings, fall back to "changes".
 96→  const experimentalSettings = useSettings().data;
 97→  const effectiveContentTab = isTabVisible(contentTab, experimentalSettings)
 98→    ? contentTab
 99→    : "changes";
100→
101→  const isBrowserDetached = useBrowserWindowStore((s) => s.detachedWindowOpen);
102→  const connectionState = useConnectionState().state;
103→  const isDisconnected = connectionState === "disconnected";
104→
105→  // --- Workspace actions (PR bridge, archive, retry, manifest) ---
106→  const {
107→    createPRHandler,
108→    setCreatePRHandler,
109→    sendAgentMessageHandler,
110→    setSendAgentMessageHandler,
111→    selectedTargetBranch,
112→    setSelectedTargetBranch,
113→    handleCreatePR,
114→    handleSendAgentMessage,
115→    handleArchive,
116→    handleRetrySetup,
117→    handleViewSetupLogs,
118→    manifestTasks,
119→    hasManifest,
120→    handleRunTask,
121→  } = useWorkspaceActions({
122→    selectedWorkspace,
123→    setContentTab,
124→  });
125→
126→  const statusMutation = useUpdateWorkspaceStatus();
127→
128→  // Only start watching and querying diffs once the worktree checkout is complete.
129→  const isReady = selectedWorkspace?.state === "ready";
130→
131→  // Watch workspace for file changes (event-driven cache invalidation)
132→  const isWatched = useFileWatcher(
133→    isReady ? (selectedWorkspace?.workspace_path ?? null) : null,
134→    isReady ? selectedWorkspaceId : null
135→  );
136→
137→  // --- Refs for imperative panel control ---
138→  const chatPanelRef = useRef<ImperativePanelHandle>(null);
139→  const contentPanelRef = useRef<ImperativePanelHandle>(null);
140→  const panelGroupContainerRef = useRef<HTMLDivElement>(null);
141→
142→  // Dynamic collapsed size: 36px strip -> percentage of container width.
143→  const MIN_PANEL_SIZE = 15;
144→  const collapsedSizePct = useCollapsedSizePercent(panelGroupContainerRef, 36);
145→  const safeCollapsedSize = Math.min(collapsedSizePct, MIN_PANEL_SIZE - 0.1);
146→
147→  // Default split: 40% session / 60% content — same for all tabs.
148→  const sessionPanelDefaultSize = 40;
149→  const contentPanelDefaultSize = 60;
150→
151→  const sessionStatus = selectedWorkspace?.session_status;
152→  const isSessionWorking = sessionStatus === "working";
153→
154→  // --- Content tab change ---
155→  const handleContentTabChange = useCallback(
156→    (tab: ContentTab) => {
157→      setContentTab(tab);
158→      // Track feature surface adoption — fire on every user-initiated tab switch.
159→      // We use a static map instead of ts-pattern here because these are all
160→      // simple string→event mappings with no branching logic.
161→      const tabEventMap: Partial<Record<ContentTab, () => void>> = {
162→        terminal: () =>
163→          track("terminal_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
164→        browser: () => track("browser_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
165→        simulator: () =>
166→          track("simulator_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
167→        changes: () => track("diff_viewed", { workspace_id: selectedWorkspaceId ?? undefined }),
168→        files: () => track("files_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
169→      };
170→      tabEventMap[tab]?.();
171→    },
172→    [setContentTab, selectedWorkspaceId]
173→  );
174→
175→  // --- Chat panel collapse/expand ---
176→  const handleCollapseChatPanel = useCallback(() => {
177→    setChatPanelCollapsed(true);
178→    chatPanelRef.current?.collapse();
179→  }, [setChatPanelCollapsed]);
180→
181→  const handleExpandChatPanel = useCallback(() => {
182→    setChatPanelCollapsed(false);
183→  }, [setChatPanelCollapsed]);
184→
185→  // --- Content panel collapse/expand ---
186→  const handleCollapseContentPanel = useCallback(() => {
187→    setContentPanelCollapsed(true);
188→    contentPanelRef.current?.collapse();
189→  }, [setContentPanelCollapsed]);
190→
191→  const handleExpandContentPanel = useCallback(() => {
192→    setContentPanelCollapsed(false);
193→  }, [setContentPanelCollapsed]);
194→
195→  // --- Keyboard shortcuts ---
196→  usePanelShortcuts({
197→    enabled: selectedWorkspace !== null && !isMobile,
198→    chatPanelCollapsed,
199→    chatPanelRef,
200→    contentPanelCollapsed,
201→    contentPanelRef,
202→  });
203→
204→  // --- Reset panel sizes on workspace switch ---
205→  // ResizablePanelGroup has no key prop — it stays mounted across workspace
206→  // switches so SimulatorPanel and BrowserPanel keep their native sessions alive.
207→  // Without the key, react-resizable-panels won't re-apply defaultSize on
208→  // re-render. We must imperatively collapse/expand panels to match the
209→  // per-workspace Zustand state when the selected workspace changes.
210→  useEffect(() => {
211→    if (!selectedWorkspaceId) return;
212→    if (chatPanelCollapsed) {
213→      chatPanelRef.current?.collapse();
214→    } else {
215→      chatPanelRef.current?.expand();
216→      chatPanelRef.current?.resize(sessionPanelDefaultSize);
217→    }
218→    if (contentPanelCollapsed) {
219→      contentPanelRef.current?.collapse();
220→    } else {
221→      contentPanelRef.current?.expand();
222→      contentPanelRef.current?.resize(contentPanelDefaultSize);
223→    }
224→    // eslint-disable-next-line react-hooks/exhaustive-deps -- only fire on workspace change, not on collapse toggles
225→  }, [selectedWorkspaceId]);
226→
227→  // --- Hide all native BrowserViews on workspace switch ---
228→  // BrowserViews are native Electron overlays rendered ABOVE the DOM. When
229→  // switching workspaces or going to the welcome screen, stale views from
230→  // the previous workspace would remain visible. Hide them immediately;
231→  // the new workspace's BrowserTab will re-show its own view when ready.
232→  useEffect(() => {
233→    native.browserViews.hideAll().catch(() => {});
234→  }, [selectedWorkspaceId]);
235→
236→  // --- Sync workspace changes to detached browser window ---
237→  const detachedWorkspaceContext = useMemo(
238→    () =>
239→      selectedWorkspace
240→        ? {
241→            workspaceId: selectedWorkspace.id,
242→            directoryName: selectedWorkspace.slug,
243→            repoName: selectedWorkspace.repo_name,
244→            branch: selectedWorkspace.git_branch,
245→          }
246→        : null,
247→    [selectedWorkspace]
248→  );
249→
250→  useEffect(() => {
251→    if (!isBrowserDetached || !detachedWorkspaceContext) return;
252→    void native.events.send(BROWSER_WORKSPACE_CHANGE, detachedWorkspaceContext);
253→  }, [isBrowserDetached, detachedWorkspaceContext]);
254→
255→  // Insert code review prompt into chat input
256→  const handleInsertReviewPrompt = useCallback(() => {
257→    workspaceChatPanelRef.current?.insertText(REVIEW_CODE);
258→  }, [workspaceChatPanelRef]);
259→
260→  return (
261→    <SidebarInset className="min-w-0">
262→      {/* Connection banner — appears at top of content area when WS is down */}
263→      <ConnectionBanner />
264→
265→      <div
266→        data-slot="main-content"
267→        className={cn(
268→          "bg-bg-surface flex h-full min-w-0 flex-1 overflow-hidden border transition-[border-radius,border-color,opacity] duration-[280ms] ease-[cubic-bezier(.19,1,.22,1)]",
269→          sidebarOpen
270→            ? "border-border-subtle rounded-l-xl border-r-0"
271→            : "rounded-none border-transparent",
272→          isDisconnected && "opacity-60"
273→        )}
274→      >
275→        {/* Sidebar toggle -- visible when sidebar collapsed (desktop) or always on mobile welcome */}
276→        {(!sidebarOpen || isMobile) && !selectedWorkspace && (
277→          <button
278→            type="button"
279→            data-slot="welcome-sidebar-toggle"
280→            aria-label="Expand sidebar"
281→            onClick={toggleSidebar}
282→            className="text-muted-foreground/60 hover:text-foreground hover:bg-foreground/5 absolute top-3 left-3 z-10 flex h-7 w-7 items-center justify-center rounded-lg transition-[transform,color,background-color] duration-200 ease-out"
283→          >
284→            <PanelLeft className="h-4 w-4" />
285→          </button>
286→        )}
287→
288→        {selectedWorkspace ? (
289→          isMobile ? (
290→            /* Mobile: single-panel layout with bottom tab bar */
291→            <MobileLayout
292→              key={selectedWorkspace.id}
293→              workspace={selectedWorkspace}
294→              workspaceChatPanelRef={workspaceChatPanelRef}
295→              sendAgentMessageHandler={sendAgentMessageHandler}
296→              handleSendAgentMessage={handleSendAgentMessage}
297→              onRetrySetup={
298→                selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
299→              }
300→              onViewSetupLogs={
301→                selectedWorkspace.setup_status === "failed" ? handleViewSetupLogs : undefined
302→              }
303→              setCreatePRHandler={setCreatePRHandler}
304→              setSendAgentMessageHandler={setSendAgentMessageHandler}
305→              isWatched={isWatched}
306→              manifestTasks={manifestTasks}
307→              hasManifest={hasManifest}
308→              onRunTask={handleRunTask}
309→              onStatusChange={(status) =>
310→                statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
311→              }
312→              prStatus={prStatus}
313→              ghStatus={ghStatus}
314→              onCreatePR={createPRHandler ? handleCreatePR : undefined}
315→              onArchive={handleArchive}
316→              targetBranch={selectedTargetBranch}
317→              onTargetBranchChange={setSelectedTargetBranch}
318→            />
319→          ) : (
320→            /* Two-panel split — the top-level layout, no full-width header */
321→            <div ref={panelGroupContainerRef} className="min-h-0 min-w-0 flex-1">
322→              <ResizablePanelGroup direction="horizontal">
323→                {/* ─── SESSION PANEL (left, collapsible) ─── */}
324→                <ResizablePanel
325→                  ref={chatPanelRef}
326→                  collapsible
327→                  collapsedSize={safeCollapsedSize}
328→                  minSize={MIN_PANEL_SIZE}
329→                  defaultSize={chatPanelCollapsed ? safeCollapsedSize : sessionPanelDefaultSize}
330→                  onCollapse={handleCollapseChatPanel}
331→                  onExpand={handleExpandChatPanel}
332→                  className="min-w-0"
333→                  order={1}
334→                >
335→                  {chatPanelCollapsed ? (
336→                    <CollapsedChatStrip
337→                      onExpand={() => chatPanelRef.current?.expand()}
338→                      isWorking={isSessionWorking}
339→                    />
340→                  ) : (
341→                    <div className="flex h-full min-w-0 flex-col">
342→                      {/* Title header — workspace name + repo/branch + Open */}
343→                      <WorkspaceHeader
344→                        title={selectedWorkspace.title ?? undefined}
345→                        repositoryName={selectedWorkspace.repo_name}
346→                        branch={selectedWorkspace.git_branch ?? undefined}
347→                        workspacePath={selectedWorkspace.workspace_path}
348→                        setupStatus={selectedWorkspace.setup_status}
349→                        setupError={selectedWorkspace.error_message}
350→                        onSendAgentMessage={
351→                          sendAgentMessageHandler ? handleSendAgentMessage : undefined
352→                        }
353→                        onRetrySetup={
354→                          selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
355→                        }
356→                        onViewSetupLogs={
357→                          selectedWorkspace.setup_status === "failed"
358→                            ? handleViewSetupLogs
359→                            : undefined
360→                        }
361→                        workspaceStatus={selectedWorkspace.status}
362→                        onStatusChange={(status) =>
363→                          statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
364→                        }
365→                        tasks={manifestTasks}
366→                        hasManifest={hasManifest}
367→                        onRunTask={handleRunTask}
368→                      />
369→
370→                      {/* Session tabs + chat messages + input */}
371→                      <ChatArea
372→                        key={selectedWorkspace.id}
373→                        workspace={selectedWorkspace}
374→                        workspaceChatPanelRef={workspaceChatPanelRef}
375→                        onCreatePRHandlerChange={setCreatePRHandler}
376→                        onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
377→                        onCollapseChatPanel={handleCollapseChatPanel}
378→                      />
379→                    </div>
380→                  )}
381→                </ResizablePanel>
382→
383→                <ResizableHandle />
384→
385→                {/* ─── CONTENT PANEL (right, collapsible) ─── */}
386→                <ResizablePanel
387→                  ref={contentPanelRef}
388→                  collapsible
389→                  collapsedSize={safeCollapsedSize}
390→                  defaultSize={contentPanelCollapsed ? safeCollapsedSize : contentPanelDefaultSize}
391→                  minSize={MIN_PANEL_SIZE}
392→                  onCollapse={handleCollapseContentPanel}
393→                  onExpand={handleExpandContentPanel}
394→                  className="min-w-0"
395→                  order={2}
396→                >
397→                  {contentPanelCollapsed ? (
398→                    <CollapsedContentStrip onExpand={() => contentPanelRef.current?.expand()} />
399→                  ) : (
400→                    <div className="flex h-full flex-col pr-2 pb-2">
401→                      {/* Tab header: content tabs (left) + PR actions (right) */}
402→                      <div className="drag-region flex h-11 flex-shrink-0 items-center justify-between px-2.5">
403→                        <ContentTabBar
404→                          activeTab={effectiveContentTab}
405→                          onTabChange={handleContentTabChange}
406→                          workspaceId={selectedWorkspaceId}
407→                        />
408→                        <PRActions
409→                          prStatus={prStatus}
410→                          ghStatus={ghStatus}
411→                          onCreatePR={createPRHandler ? handleCreatePR : undefined}
412→                          onSendAgentMessage={
413→                            sendAgentMessageHandler ? handleSendAgentMessage : undefined
414→                          }
415→                          onArchive={handleArchive}
416→                          targetBranch={selectedTargetBranch}
417→                          onTargetBranchChange={setSelectedTargetBranch}
418→                          workspacePath={selectedWorkspace.workspace_path}
419→                          repoId={selectedWorkspace.repository_id}
420→                          workspaceId={selectedWorkspaceId ?? undefined}
421→                        />
422→                      </div>
423→
424→                      {/* Content area — rounded corners, subtle border */}
425→                      <div className="border-border-subtle bg-bg-elevated flex min-h-0 flex-1 overflow-hidden rounded-lg border">
426→                        <ContentView
427→                          workspace={selectedWorkspace}
428→                          activeTab={effectiveContentTab}
429→                          isWatched={isWatched}
430→                          onReview={handleInsertReviewPrompt}
431→                        />
432→                      </div>
433→                    </div>
434→                  )}
435→                </ResizablePanel>
436→              </ResizablePanelGroup>
437→            </div>
438→          )
439→        ) : (
440→          <div className="flex min-w-0 flex-1">
441→            <WelcomeView
442→              repos={repos}
443→              onSendMessage={onSendFromWelcome}
444→              onOpenProject={onOpenProject}
445→              onCloneRepository={onCloneRepository}
446→              sending={welcomeSending}
447→            />
448→          </div>
449→        )}
450→      </div>
451→    </SidebarInset>
452→  );
453→}
