 60→/**
 61→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 62→ * Must be rendered inside SidebarProvider to access sidebar open state.
 63→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 64→ */
 65→function SidebarResizeHandle({
 66→  onSizeChange,
 67→  onDraggingChange,
 68→}: {
 69→  onSizeChange: (size: number | null) => void;
 70→  onDraggingChange: (dragging: boolean) => void;
 71→}) {
 72→  const { open } = useSidebar();
 73→
 74→  const { handleProps, isDragging } = useResizeHandle({
 75→    onSizeChange,
 76→    enabled: open,
 77→    direction: "horizontal",
 78→    mode: "primary",
 79→    minPrimarySize: 200,
 80→    minSecondarySize: 400,
 81→  });
 82→
 83→  // Notify parent of drag state changes to disable sidebar transitions
 84→  useEffect(() => {
 85→    onDraggingChange(isDragging);
 86→  }, [isDragging, onDraggingChange]);
 87→
 88→  if (!open) return null;
 89→
 90→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 91→}
