 93→export function MainLayout() {
 94→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 95→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 96→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 97→  const expandRepo = useSidebarStore((s) => s.expandRepo);
 98→
 99→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
100→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
101→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
102→  const settingsOpen = useUIStore((s) => s.settingsOpen);
103→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
104→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
105→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
106→
107→  // TanStack Query
108→  const workspacesQuery = useWorkspacesByRepo();
109→
110→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
111→  const loading = workspacesQuery.isLoading;
112→
113→  // Derive the full workspace object from React Query data.
114→  // The store only holds an ID; this useMemo resolves it to a Workspace
115→  // on every React Query refresh, eliminating the old sync effect entirely.
116→  const selectedWorkspace = useMemo(() => {
117→    if (!selectedWorkspaceId || !repoGroups.length) return null;
118→    for (const group of repoGroups) {
119→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
120→      if (found) return found;
121→    }
122→    return null;
123→  }, [selectedWorkspaceId, repoGroups]);
124→
125→  const selectedWorkspaceIdRef = useRef(selectedWorkspaceId);
126→  useEffect(() => {
127→    selectedWorkspaceIdRef.current = selectedWorkspaceId;
128→  });
129→
130→  // Bulk-fetch diff stats for all workspaces (replaces per-item useDiffStats in sidebar)
131→  const bulkDiffStatsQuery = useBulkDiffStats(repoGroups);
132→
133→  // Sidebar resize: null = default 344px, number = user-set width
134→  const [sidebarWidth, setSidebarWidth] = useState<number | null>(null);
135→  // Tracks drag state to disable sidebar CSS transitions during resize
136→  const [sidebarDragging, setSidebarDragging] = useState(false);
137→
138→  // GitHub picker modal state
139→  const [githubPickerRepoId, setGithubPickerRepoId] = useState<string | null>(null);
140→
141→  // Ref for inserting text from browser element selector
142→  const workspaceChatPanelRef = useRef<SessionPanelRef | null>(null);
143→
144→  // Queries for repos, settings
145→  const reposQuery = useRepos();
146→  const settingsQuery = useSettingsQuery();
147→
148→  const repos = reposQuery.data || [];
149→  const username = settingsQuery.data?.user_name || "My Account";
150→
151→  // GitHub CLI status — gates PR polling
152→  const ghStatusQuery = useGhStatus();
153→
154→  // PR status query — gated on gh CLI, polls while agent is working
155→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
156→    ghInstalled: ghStatusQuery.data?.isInstalled,
157→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
158→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
159→  });
160→
161→  // --- Extracted hooks ---
162→
163→  const repoActions = useRepoActions({
164→    selectWorkspace,
165→    openNewWorkspaceModal,
166→    closeNewWorkspaceModal,
167→  });
168→
169→  // --- Welcome screen send flow ---
170→  // When the user sends a message from the welcome screen, we:
171→  // 1. Create a workspace for the selected repo
172→  // 2. Select it (transitions to two-panel layout)
173→  // 3. Queue the message to be sent once the workspace has a session
174→  const welcomeCreateMutation = useCreateWorkspace();
175→  const [welcomeSending, setWelcomeSending] = useState(false);
176→  const pendingWelcomeMessageRef = useRef<{
177→    message: string;
178→    model: string;
179→    workspaceId: string;
180→  } | null>(null);
181→
182→  const handleSendFromWelcome = useCallback(
183→    async (repoId: string, message: string, model: string, branch?: string) => {
184→      if (welcomeSending) return;
185→      setWelcomeSending(true);
186→
187→      try {
188→        const workspace = await welcomeCreateMutation.mutateAsync(
189→          branch ? { repositoryId: repoId, source_branch: branch } : repoId
190→        );
191→        // Store pending message — will be sent when workspace gets a session
192→        pendingWelcomeMessageRef.current = {
193→          message,
194→          model,
195→          workspaceId: workspace.id,
196→        };
197→        selectWorkspace(workspace.id);
198→        expandRepo(workspace.repository_id);
199→      } catch (error) {
200→        console.error("Failed to create workspace from welcome:", error);
201→        toast.error(getErrorMessage(error));
202→        pendingWelcomeMessageRef.current = null;
203→      } finally {
204→        setWelcomeSending(false);
205→      }
206→    },
207→    [welcomeSending, welcomeCreateMutation, selectWorkspace, expandRepo]
208→  );
209→
210→  // Effect: when the pending workspace becomes ready with a session, send the queued message
211→  useEffect(() => {
212→    const pending = pendingWelcomeMessageRef.current;
213→    if (!pending) return;
214→    if (!selectedWorkspace) return;
215→    if (selectedWorkspace.id !== pending.workspaceId) return;
216→    // Workspace must be ready with a session
217→    if (selectedWorkspace.state !== "ready" || !selectedWorkspace.current_session_id) return;
218→    if (!selectedWorkspace.workspace_path) return;
219→
220→    // Clear the pending ref before sending to prevent double-fire
221→    const { message, model } = pending;
222→    pendingWelcomeMessageRef.current = null;
223→
224→    const sessionId = selectedWorkspace.current_session_id;
225→    const cwd = selectedWorkspace.workspace_path;
226→    const runtimeModelId = getRuntimeModelId(model);
227→    const agentType = getRuntimeAgentTypeForModel(model);
228→
229→    // Fire-and-forget: send the message via WS command
230→    (async () => {
231→      try {
232→        if (!isConnected()) await connect();
233→        const ack = await sendCommand("sendMessage", {
234→          sessionId,
235→          content: message,
236→          model: runtimeModelId,
237→          cwd,
238→          agentType,
239→        });
240→        if (!ack.accepted) {
241→          toast.error(ack.error || "Failed to send message");
242→        }
243→      } catch (error) {
244→        console.error("Failed to send welcome message:", error);
245→        toast.error(getErrorMessage(error));
246→      }
247→    })();
248→  }, [selectedWorkspace]);
249→
250→  // Derive repo name for GitHub picker modal from repoGroups
251→  const githubPickerRepoName = useMemo(() => {
252→    if (!githubPickerRepoId) return "";
253→    const group = repoGroups.find((g) => g.repo_id === githubPickerRepoId);
254→    return group?.repo_name ?? "";
255→  }, [githubPickerRepoId, repoGroups]);
256→
257→  // Hide native WebContentsViews when any dialog is open — they render above
258→  // the DOM so dialogs would appear behind them. BrowserTab's own visible
259→  // effect handles re-showing when the dialog closes.
260→  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
261→  const anyDialogOpen =
262→    showNewWorkspaceModal ||
263→    showSystemPromptModal ||
264→    commandPaletteOpen ||
265→    !!githubPickerRepoId ||
266→    repoActions.showCloneModal;
267→  useEffect(() => {
268→    if (anyDialogOpen) {
269→      native.browserViews.hideAll().catch(() => {});
270→    }
271→  }, [anyDialogOpen]);
272→
273→  // --- System prompt (inline — small scope, one modal) ---
274→
275→  const systemPromptQuery = useSystemPrompt(selectedWorkspace?.id || null);
276→  const updateSystemPromptMutation = useUpdateSystemPrompt();
277→  // Track user edits separately; reset to null when modal closes so the
278→  // derived value from the query takes over again (no useEffect + setState).
279→  const [systemPromptEdit, setSystemPromptEdit] = useState<string | null>(null);
280→  const systemPromptDraft = systemPromptEdit ?? (systemPromptQuery.data || "");
281→  const setSystemPromptDraft = useCallback((value: string) => setSystemPromptEdit(value), []);
282→
283→  async function saveSystemPrompt() {
284→    if (!selectedWorkspace) return;
285→    try {
286→      await updateSystemPromptMutation.mutateAsync({
287→        workspaceId: selectedWorkspace.id,
288→        systemPrompt: systemPromptDraft,
289→      });
290→      closeSystemPromptModal();
291→      setSystemPromptEdit(null);
292→    } catch (error) {
293→      console.error("Failed to save system prompt:", error);
294→      toast.error(getErrorMessage(error));
295→    }
296→  }
297→
298→  // --- Archive with undo (ref-stable for memoized sidebar items) ---
299→
300→  const archiveWorkspaceMutation = useArchiveWorkspace();
301→  const unarchiveMutation = useUnarchiveWorkspace();
302→
303→  // Ref-stable archive handler: archiveWorkspaceMutation and selectedWorkspace
304→  // change frequently (every render / every workspace click), so we capture
305→  // them in refs to keep the callback identity stable. This matters because
306→  // onArchive flows through the entire sidebar tree to every memoized WorkspaceItem.
307→  const archiveMutationRef = useRef(archiveWorkspaceMutation);
308→  const unarchiveMutationRef = useRef(unarchiveMutation);
309→  const selectedWorkspaceRef = useRef(selectedWorkspace);
310→  useEffect(() => {
311→    archiveMutationRef.current = archiveWorkspaceMutation;
312→    unarchiveMutationRef.current = unarchiveMutation;
313→    selectedWorkspaceRef.current = selectedWorkspace;
314→  });
315→
316→  const archiveWorkspace = useCallback(
317→    async (workspaceId: string) => {
318→      try {
319→        await archiveMutationRef.current.mutateAsync(workspaceId);
320→        if (selectedWorkspaceRef.current?.id === workspaceId) {
321→          selectWorkspace(null);
322→        }
323→        toast("Workspace archived", {
324→          duration: 5000,
325→          action: {
326→            label: "Undo",
327→            onClick: () => {
328→              unarchiveMutationRef.current.mutateAsync(workspaceId).catch((error) => {
329→                toast.error(getErrorMessage(error));
330→              });
331→            },
332→          },
333→        });
334→      } catch (error) {
335→        console.error("Error archiving workspace:", error);
336→        toast.error(getErrorMessage(error));
337→      }
338→    },
339→    [selectWorkspace]
340→  );
341→
342→  // --- Workflow status change (ref-stable like archive) ---
343→
344→  const statusMutation = useUpdateWorkspaceStatus();
345→  const statusMutationRef = useRef(statusMutation);
346→  useEffect(() => {
347→    statusMutationRef.current = statusMutation;
348→  });
349→
350→  const handleStatusChange = useCallback(
351→    (workspaceId: string, status: import("@shared/enums").WorkspaceStatus) => {
352→      statusMutationRef.current.mutate(
353→        { workspaceId, status },
354→        { onError: (error) => toast.error(getErrorMessage(error)) }
355→      );
356→    },
357→    []
358→  );
359→
360→  // --- Global hooks ---
361→
362→  // Connection state machine — subscribes to WS changes + send-attempt-failed events
363→  useConnectionStateInit();
364→
365→  // Zoom (Cmd+=/Cmd+-/Cmd+0)
366→  useZoom();
367→
