516→        onRepoChange={repoActions.setSelectedRepoId}
517→        onCreate={
518→          newWorkspaceMode === "from-github"
519→            ? () => {
520→                const repoId = repoActions.selectedRepoId;
521→                closeNewWorkspaceModal();
