523→              }
524→            : repoActions.createWorkspaceFromModal
525→        }
526→        mode={newWorkspaceMode}
527→      />
528→
529→      <SystemPromptModal
530→        show={showSystemPromptModal && !!selectedWorkspace}
531→        workspaceName={selectedWorkspace?.slug || ""}
532→        systemPrompt={systemPromptDraft}
533→        loading={systemPromptQuery.isLoading}
534→        saving={updateSystemPromptMutation.isPending}
535→        onClose={() => {
536→          closeSystemPromptModal();
537→          setSystemPromptEdit(null);
538→        }}
539→        onChange={setSystemPromptDraft}
540→        onSave={saveSystemPrompt}
541→      />
542→
543→      <CloneRepositoryModal
544→        show={repoActions.showCloneModal}
545→        cloning={repoActions.cloning}
546→        error={repoActions.cloneError}
547→        statusMessage={repoActions.cloneStatus}
548→        onClose={repoActions.closeCloneModal}
549→        onClone={repoActions.handleCloneRepository}
550→        onClearError={repoActions.clearCloneError}
551→      />
552→
553→      <GitHubPickerModal
554→        open={!!githubPickerRepoId}
555→        onOpenChange={(open) => !open && setGithubPickerRepoId(null)}
556→        repoId={githubPickerRepoId || ""}
557→        repoName={githubPickerRepoName}
558→        onCreateWorkspace={repoActions.handleNewWorkspaceFromGitHub}
559→      />
560→
561→      {/* Command Palette (Cmd+K) */}
562→      <CommandPalette
563→        actionOverrides={{
564→          "open-project": repoActions.handleOpenProject,
