  1→/**
  2→ * Workspace Initialization Pipeline
  3→ *
  4→ * Orchestrates the multi-step process of creating a workspace:
  5→ *   1. git worktree add (fatal — cleanup on failure)
  6→ *   2. Dependency installation via lockfile-detected PM (non-fatal)
  7→ *   3. Post-create hooks: .env / .env.local copy (non-fatal)
  8→ *   4. Git clean: restore tracked files so diff starts at zero (non-fatal)
  9→ *   5. Session creation + state transition to 'ready' (fatal)
 10→ *
 11→ * Each step updates the workspace's `init_stage` column in DB and emits
 12→ * a structured stdout line that Electron main process parses and relays as an IPC event:
 13→ *   DEUS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
 14→ *
 15→ * Design decisions:
 16→ * - Pipeline runs in-process (async), not as spawned child — proper try/catch
 17→ * - Non-fatal steps (deps, hooks) log warnings but don't block workspace creation
 18→ * - Reverse-order cleanup on fatal failure: rm dir → prune worktree → delete branch
 19→ * - Structured init pipeline with deps install
 20→ */
 21→
 22→import fs from "fs";
 23→import path from "path";
 24→import { execFile } from "child_process";
 25→import { promisify } from "util";
 26→import { uuidv7 } from "@shared/lib/uuid";
 27→import { getDatabase } from "../lib/database";
 28→import { invalidate } from "./query-engine";
 29→
 30→const execFileAsync = promisify(execFile);
 31→
 32→/** Check if an error is a retryable SQLite concurrency error (BUSY / locked). */
 33→export function isRetryableDbError(err: unknown): boolean {
 34→  if (!(err instanceof Error)) return false;
 35→  const msg = err.message.toLowerCase();
 36→  return (
 37→    msg.includes("sqlite_busy") ||
 38→    msg.includes("database is locked") ||
 39→    msg.includes("database is busy")
 40→  );
 41→}
 42→
 43→// ─── Types ──────────────────────────────────────────────────────
 44→
 45→export interface InitContext {
 46→  workspaceId: string;
 47→  repositoryId: string;
 48→  repoRootPath: string;
 49→  workspacePath: string;
 50→  branchName: string;
 51→  worktreeBase: string;
 52→  parentBranch: string;
 53→}
 54→
 55→interface InitStage {
 56→  name: string;
 57→  label: string;
 58→  fatal: boolean;
 59→  run: (ctx: InitContext) => Promise<void>;
 60→  cleanup?: (ctx: InitContext) => Promise<void>;
 61→}
 62→
 63→// ─── Progress Emission ──────────────────────────────────────────
 64→
 65→/**
 66→ * Emit workspace init progress via stdout JSON protocol.
 67→ * Electron's backend-process.ts reads stdout line-by-line and relays lines
 68→ * prefixed with DEUS_WORKSPACE_PROGRESS: as IPC events.
 69→ */
 70→export function emitProgress(workspaceId: string, step: string, label: string): void {
 71→  const payload = JSON.stringify({ workspaceId, step, label });
 72→  process.stdout.write(`DEUS_WORKSPACE_PROGRESS:${payload}\n`);
 73→}
 74→
 75→function updateInitStage(workspaceId: string, stage: string): void {
 76→  const db = getDatabase();
 77→  db.prepare("UPDATE workspaces SET init_stage = ? WHERE id = ?").run(stage, workspaceId);
 78→}
 79→
 80→// ─── Package Manager Detection ──────────────────────────────────
 81→
 82→interface PackageManager {
 83→  command: string;
 84→  args: string[];
 85→}
 86→
 87→/**
 88→ * Detect the package manager from lockfile presence in the workspace.
 89→ * Returns null if no package.json exists (nothing to install).
 90→ */
 91→export function detectPackageManager(dir: string): PackageManager | null {
 92→  // Check lockfiles in priority order (bun first — project default)
 93→  if (fs.existsSync(path.join(dir, "bun.lock")) || fs.existsSync(path.join(dir, "bun.lockb"))) {
 94→    return { command: "bun", args: ["install", "--frozen-lockfile"] };
 95→  }
 96→  if (fs.existsSync(path.join(dir, "yarn.lock"))) {
 97→    return { command: "yarn", args: ["install", "--frozen-lockfile"] };
 98→  }
 99→  if (fs.existsSync(path.join(dir, "pnpm-lock.yaml"))) {
100→    return { command: "pnpm", args: ["install", "--frozen-lockfile"] };
101→  }
102→  if (fs.existsSync(path.join(dir, "package-lock.json"))) {
103→    return { command: "npm", args: ["ci"] };
104→  }
105→  // package.json exists but no lockfile — try npm install
106→  if (fs.existsSync(path.join(dir, "package.json"))) {
107→    return { command: "npm", args: ["install"] };
108→  }
109→  return null;
110→}
111→
112→// ─── Cleanup ────────────────────────────────────────────────────
113→
114→async function cleanupWorktree(
115→  repoRootPath: string,
116→  workspacePath: string,
117→  branchName: string
118→): Promise<void> {
119→  // Remove worktree directory
120→  try {
121→    if (fs.existsSync(workspacePath)) {
122→      fs.rmSync(workspacePath, { recursive: true, force: true });
123→    }
124→  } catch (e) {
125→    console.warn("[WORKSPACE] Failed to remove worktree directory:", e);
126→  }
127→
128→  // Prune git worktree references
129→  try {
130→    await execFileAsync("git", ["worktree", "prune"], {
131→      cwd: repoRootPath,
132→      timeout: 5_000,
133→    });
134→  } catch (e) {
135→    console.warn("[WORKSPACE] Failed to prune worktrees:", e);
136→  }
137→
138→  // Delete the orphaned branch
139→  try {
140→    await execFileAsync("git", ["branch", "-D", branchName], {
141→      cwd: repoRootPath,
142→      timeout: 5_000,
143→    });
144→  } catch {
145→    // Branch may not have been created — that's fine
146→  }
