 32→import { useSettings } from "@/features/settings/api/settings.queries";
 33→import { SidebarInset, useSidebar } from "@/components/ui";
 34→import { cn } from "@/shared/lib/utils";
 35→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 36→import { PanelLeft } from "lucide-react";
 37→import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
 38→import { useUpdateWorkspaceStatus } from "@/features/workspace/api";
 39→import { REVIEW_CODE } from "@/features/session/lib/sessionPrompts";
 40→import { native } from "@/platform";
 41→import { BROWSER_WORKSPACE_CHANGE } from "@shared/events";
 42→import { useBrowserWindowStore } from "@/features/browser/store";
 43→import { track } from "@/platform/analytics";
 44→import { ConnectionBanner, useConnectionState } from "@/features/connection";
 45→import { useIsMobile } from "@/shared/hooks/use-mobile";
 46→import { ChatArea } from "./ChatArea";
 47→import { ContentView } from "./ContentView";
 48→import { MobileLayout } from "./MobileLayout";
