 52→
 53→interface MainContentProps {
 54→  selectedWorkspace: Workspace | null;
 55→  prStatus: PRStatus | null;
 56→  ghStatus?: GhCliStatus | null;
 57→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
