    msg.includes("sqlite_busy") ||
    msg.includes("database is locked") ||
    msg.includes("database is busy")
  );
}

// ─── Types ──────────────────────────────────────────────────────

export interface InitContext {
  workspaceId: string;
  repositoryId: string;
  repoRootPath: string;
  workspacePath: string;
