// ─── Hoisted mocks (vi.mock factories run before imports) ─────────

const { mockStmt, mockDb, mockExecFileAsync, mockFs } = vi.hoisted(() => {
  const mockStmt = {
    run: vi.fn(() => ({ changes: 1 })),
    get: vi.fn(),
    all: vi.fn(() => []),
  };
  const mockDb = {
    prepare: vi.fn(() => mockStmt),
