      .filter((c: string[]) => c[0].includes("init_stage = ?"))
      .map((c: string[]) => c[0]);

    // Should update init_stage for worktree, dependencies, hooks, session (+ session sets 'done')
    expect(initStageUpdates.length).toBeGreaterThanOrEqual(4);
  });

