154→  // PR status query — gated on gh CLI, polls while agent is working
155→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
156→    ghInstalled: ghStatusQuery.data?.isInstalled,
157→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
158→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
159→  });
160→
161→  // --- Extracted hooks ---
162→
163→  const repoActions = useRepoActions({
164→    selectWorkspace,
165→    openNewWorkspaceModal,
166→    closeNewWorkspaceModal,
167→  });
168→
169→  // --- Welcome screen send flow ---
170→  // When the user sends a message from the welcome screen, we:
171→  // 1. Create a workspace for the selected repo
172→  // 2. Select it (transitions to two-panel layout)
173→  // 3. Queue the message to be sent once the workspace has a session
174→  const welcomeCreateMutation = useCreateWorkspace();
175→  const [welcomeSending, setWelcomeSending] = useState(false);
176→  const pendingWelcomeMessageRef = useRef<{
177→    message: string;
178→    model: string;
179→    workspaceId: string;
180→  } | null>(null);
181→
182→  const handleSendFromWelcome = useCallback(
183→    async (repoId: string, message: string, model: string, branch?: string) => {
184→      if (welcomeSending) return;
185→      setWelcomeSending(true);
186→
187→      try {
188→        const workspace = await welcomeCreateMutation.mutateAsync(
189→          branch ? { repositoryId: repoId, source_branch: branch } : repoId
190→        );
191→        // Store pending message — will be sent when workspace gets a session
192→        pendingWelcomeMessageRef.current = {
193→          message,
194→          model,
195→          workspaceId: workspace.id,
196→        };
197→        selectWorkspace(workspace.id);
198→        expandRepo(workspace.repository_id);
199→      } catch (error) {
200→        console.error("Failed to create workspace from welcome:", error);
201→        toast.error(getErrorMessage(error));
202→        pendingWelcomeMessageRef.current = null;
203→      } finally {
204→        setWelcomeSending(false);
205→      }
206→    },
207→    [welcomeSending, welcomeCreateMutation, selectWorkspace, expandRepo]
208→  );
209→
210→  // Effect: when the pending workspace becomes ready with a session, send the queued message
211→  useEffect(() => {
212→    const pending = pendingWelcomeMessageRef.current;
213→    if (!pending) return;
214→    if (!selectedWorkspace) return;
215→    if (selectedWorkspace.id !== pending.workspaceId) return;
216→    // Workspace must be ready with a session
217→    if (selectedWorkspace.state !== "ready" || !selectedWorkspace.current_session_id) return;
218→    if (!selectedWorkspace.workspace_path) return;
219→
220→    // Clear the pending ref before sending to prevent double-fire
221→    const { message, model } = pending;
222→    pendingWelcomeMessageRef.current = null;
223→
224→    const sessionId = selectedWorkspace.current_session_id;
225→    const cwd = selectedWorkspace.workspace_path;
226→    const runtimeModelId = getRuntimeModelId(model);
227→    const agentType = getRuntimeAgentTypeForModel(model);
228→
229→    // Fire-and-forget: send the message via WS command
230→    (async () => {
231→      try {
232→        if (!isConnected()) await connect();
233→        const ack = await sendCommand("sendMessage", {
234→          sessionId,
235→          content: message,
236→          model: runtimeModelId,
237→          cwd,
238→          agentType,
239→        });
240→        if (!ack.accepted) {
241→          toast.error(ack.error || "Failed to send message");
242→        }
243→      } catch (error) {
244→        console.error("Failed to send welcome message:", error);
245→        toast.error(getErrorMessage(error));
246→      }
247→    })();
248→  }, [selectedWorkspace]);
249→
250→  // Derive repo name for GitHub picker modal from repoGroups
251→  const githubPickerRepoName = useMemo(() => {
