 70→/**
 71→ * Subscribe to per-session working status for multiple sessions at once.
 72→ * Used by the tab bar to show per-tab spinners and unread detection.
 73→ *
 74→ * Subscribes each session to WS push so status transitions arrive in real
 75→ * time — even for non-active tabs. Without this, only the active tab
 76→ * (via useSession) receives WS updates; background tabs rely on stale
 77→ * HTTP cache and never trigger unread detection.
 78→ */
 79→export function useWorkingSessionIds(sessionIds: string[]): Set<string> {
 80→  const queryClient = useQueryClient();
 81→
 82→  // WS-subscribe all tab sessions so status pushes keep the cache fresh.
 83→  const stableKey = useMemo(() => sessionIds.join(","), [sessionIds]);
 84→  useEffect(() => {
 85→    if (!sessionIds.length) return;
 86→    const unsubs = sessionIds.map((id) =>
 87→      subscribe("session", { sessionId: id }, (data) => {
 88→        queryClient.setQueryData(queryKeys.sessions.detail(id), data);
 89→      })
 90→    );
 91→    return () => unsubs.forEach((u) => u());
 92→    // eslint-disable-next-line react-hooks/exhaustive-deps
 93→  }, [stableKey, queryClient]);
 94→
 95→  const queries = useQueries({
 96→    queries: sessionIds.map((id) => ({
 97→      queryKey: queryKeys.sessions.detail(id),
 98→      queryFn: () => SessionService.fetchById(id),
 99→      staleTime: Infinity, // WS handles freshness now
100→      refetchOnWindowFocus: false,
101→      select: (data: Session): SessionStatus => data.status,
102→    })),
103→  });
104→
105→  return useMemo(() => {
106→    const ids = new Set<string>();
107→    sessionIds.forEach((id, i) => {
108→      if (queries[i]?.data === "working") ids.add(id);
109→    });
110→    return ids;
111→  }, [queries, sessionIds]);
112→}
