174→        blocks.filter(isToolResultBlock).forEach((block) => {
175→          resultMap.set(block.tool_use_id, block);
176→        });
177→      }
178→    });
179→
180→    return { toolResultMap: resultMap, parentToolUseMap: parentMap };
181→  }, [messages, parseContent]);
182→
183→  // Group subagent messages by their parent Task tool_use_id
184→  const subagentMessages = useMemo(() => {
185→    const map = new Map<string, Message[]>();
186→    if (!messages.length) return map;
187→
188→    messages.forEach((msg: Message) => {
189→      const parentId = parentToolUseMap.get(msg.id);
190→      if (parentId) {
191→        if (!map.has(parentId)) map.set(parentId, []);
192→        map.get(parentId)!.push(msg);
193→      }
194→    });
195→
196→    return map;
197→  }, [messages, parentToolUseMap]);
198→
199→  // Get latest user message's sent_at for duration tracking
200→  const latestMessageSentAt = useMemo(() => {
201→    if (!messages.length) return null;
202→
203→    // Find the latest user message
204→    const latestUserMessage = [...messages].reverse().find((msg: Message) => msg.role === "user");
205→
206→    return latestUserMessage?.sent_at || null;
207→  }, [messages]);
208→
209→  return {
210→    session: sessionQuery.data,
211→    messages,
212→    hasOlder,
213→    sessionStatus: (sessionQuery.data?.status as SessionStatus) || "idle",
214→    latestMessageSentAt,
215→    loading: sessionQuery.isLoading || messagesQuery.isLoading,
216→    error: sessionQuery.error || messagesQuery.error,
217→    parseContent,
218→    toolResultMap,
219→    parentToolUseMap,
220→    subagentMessages,
221→  };
222→}
