224→/**
225→ * Load older messages (scroll-up pagination).
226→ * Prepends older messages to the cache while preserving has_newer from current cache.
227→ */
228→export function useLoadOlderMessages() {
229→  const queryClient = useQueryClient();
230→
231→  return useMutation({
232→    mutationFn: ({ sessionId, beforeSeq }: { sessionId: string; beforeSeq: number }) =>
233→      SessionService.fetchMessages(sessionId, { before: beforeSeq, limit: MESSAGE_PAGE_SIZE }),
234→
235→    onSuccess: (olderPage, { sessionId }) => {
236→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
237→        if (!old) return olderPage;
238→        // Deduplicate by id (shouldn't happen, but safety first)
239→        const existingIds = new Set(old.messages.map((m) => m.id));
240→        const newMessages = olderPage.messages.filter((m) => !existingIds.has(m.id));
241→        return {
242→          messages: [...newMessages, ...old.messages],
243→          has_older: olderPage.has_older,
244→          has_newer: old.has_newer,
245→        };
246→      });
247→    },
248→  });
249→}
