251→/**
252→ * Send message mutation with optimistic update
253→ *
254→ * Shows user message immediately in the chat while request is in flight.
255→ * The optimistic message has a temporary ID that gets replaced on refetch.
256→ */
257→export function useSendMessage() {
258→  const queryClient = useQueryClient();
259→
260→  return useMutation({
261→    mutationFn: async ({
262→      sessionId,
263→      content,
264→      model,
265→      cwd,
266→      agentType,
267→      permissionMode,
268→    }: {
269→      sessionId: string;
270→      content: string;
271→      model?: string;
272→      cwd?: string;
273→      agentType?: RuntimeAgentType;
274→      permissionMode?: string;
275→    }): Promise<Message | void> => {
276→      // Send message via WS command: backend saves user message to DB,
277→      // forwards to agent-server, and pushes q:delta to subscribers.
278→      if (cwd) {
279→        if (!isConnected()) await connect();
280→        const ack = await sendCommand("sendMessage", {
281→          sessionId,
282→          content,
283→          model,
284→          cwd,
285→          agentType: agentType || "claude",
286→          permissionMode,
287→        });
288→        if (!ack.accepted) {
289→          throw new Error(ack.error || "Agent rejected the query");
290→        }
291→        // No return value needed — WS q:delta handles message reconciliation.
292→        return;
293→      }
294→      // Gateway/web fallback: HTTP POST to backend
295→      return SessionService.sendMessage(sessionId, content, model);
296→    },
297→
298→    // Optimistic update: show user message immediately.
299→    // Status indicators (tab spinner, sidebar) are updated by the workspaces
300→    // WS subscription — the agent-server notifies the backend, which pushes fresh
301→    // workspace snapshots within ~50ms.
302→    onMutate: async ({ sessionId, content, model }) => {
303→      await queryClient.cancelQueries({
304→        queryKey: queryKeys.sessions.messages(sessionId),
305→      });
306→
307→      const previousMessages = queryClient.getQueryData<PaginatedMessages>(
308→        queryKeys.sessions.messages(sessionId)
309→      );
310→
311→      // Snapshot workspace-by-repo cache before optimistic update so we can
312→      // restore the exact prior status on error (instead of hardcoding "idle").
313→      const previousWorkspaceByRepo = queryClient.getQueriesData<RepoGroup[]>({
314→        queryKey: ["workspaces", "by-repo"],
315→      });
316→
317→      // Create optimistic user message
318→      const optimisticId =
319→        typeof crypto !== "undefined" && "randomUUID" in crypto
320→          ? `optimistic-${crypto.randomUUID()}`
321→          : `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
322→
323→      // Content may be plain text or a JSON-stringified content blocks array (when images attached).
324→      let optimisticContentJson: string;
325→      try {
326→        const parsed = JSON.parse(content);
327→        if (Array.isArray(parsed)) {
328→          optimisticContentJson = JSON.stringify(parsed);
329→        } else {
330→          optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
331→        }
332→      } catch {
333→        optimisticContentJson = JSON.stringify([{ type: "text", text: content }]);
334→      }
335→
336→      const optimisticMessage: Message = {
337→        id: optimisticId,
338→        session_id: sessionId,
339→        seq: Number.MAX_SAFE_INTEGER,
340→        role: "user",
341→        content: optimisticContentJson,
342→        sent_at: new Date().toISOString(),
343→        model: model ?? null,
344→      };
345→
346→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
347→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
348→        return produce(old, (draft) => {
349→          draft.messages.push(optimisticMessage);

345→
346→      queryClient.setQueryData<PaginatedMessages>(queryKeys.sessions.messages(sessionId), (old) => {
347→        if (!old) return { messages: [optimisticMessage], has_older: false, has_newer: false };
348→        return produce(old, (draft) => {
349→          draft.messages.push(optimisticMessage);
350→        });
351→      });
352→
353→      // Optimistically set workspace status to "working" in sidebar cache.
354→      // Handles the startup race where the first IPC event arrives before
355→      // the workspace list has loaded (cache empty → event matching fails).
356→      queryClient.setQueriesData<RepoGroup[]>({ queryKey: ["workspaces", "by-repo"] }, (old) => {
357→        if (!old) return old;
358→        return old.map((group) => ({
359→          ...group,
360→          workspaces: group.workspaces.map((ws) =>
361→            ws.current_session_id === sessionId
362→              ? { ...ws, session_status: "working" as SessionStatus }
363→              : ws
364→          ),
365→        }));
366→      });
367→
368→      return { previousMessages, previousWorkspaceByRepo };
369→    },
370→
371→    onError: (_err, variables, context) => {
372→      // If the error is a WS connectivity issue, escalate the connection state
373→      // immediately. The WS client produces three distinct error messages:
374→      //   "WebSocket not connected"     — socket already down before send
375→      //   "WebSocket disconnected"      — connection dropped mid-flight
376→      //   "WebSocket connection failed" — connect() rejected (initial open failed)
377→      if (_err instanceof Error) {
378→        const msg = _err.message.toLowerCase();
379→        if (
380→          msg.includes("not connected") ||
381→          msg.includes("disconnected") ||
382→          msg.includes("connection failed")
383→        ) {
384→          emitSendAttemptFailed();
385→        }
386→      }
387→      // Roll back optimistic message
388→      if (context?.previousMessages) {
389→        queryClient.setQueryData(
390→          queryKeys.sessions.messages(variables.sessionId),
391→          context.previousMessages
392→        );
393→      } else {
394→        // No snapshot (first send on empty cache) — invalidate to clear the ghost optimistic message
395→        queryClient.invalidateQueries({
396→          queryKey: queryKeys.sessions.messages(variables.sessionId),
397→        });
398→      }
399→      // Roll back optimistic workspace status from snapshot
400→      if (context?.previousWorkspaceByRepo?.length) {
401→        context.previousWorkspaceByRepo.forEach(([key, data]) => {
402→          queryClient.setQueryData(key, data);
403→        });
404→      } else {
405→        queryClient.invalidateQueries({ queryKey: ["workspaces", "by-repo"] });
406→      }
407→    },
408→
409→    onSettled: async (_, error, variables) => {
410→      if (!error) {
411→        const hasImages = (() => {
412→          try {
413→            const parsed = JSON.parse(variables.content);
414→            return (
415→              Array.isArray(parsed) && parsed.some((b: { type?: string }) => b.type === "image")
416→            );
417→          } catch {
418→            return false;
419→          }
420→        })();
421→        const session = queryClient.getQueryData<Session>(
422→          queryKeys.sessions.detail(variables.sessionId)
423→        );
424→        track("session_message_sent", {
425→          session_id: variables.sessionId,
426→          has_images: hasImages,
427→          model: variables.model,
428→          agent_type: session?.agent_type,
429→          message_count: session?.message_count,
430→          context_used_percent: session?.context_used_percent,
431→        });
432→      }
433→      // No incrementalFetchAndMerge needed — WS q:delta handles reconciliation.
434→      // The optimistic message stays visible until the delta arrives with the real message.
435→    },
436→  });
437→}
