143→        {/* Workspace still initializing — show the same empty state with init progress */}
144→        {!tabSessionId && (
145→          <WorkspaceEmptyState
146→            repoName={workspace.repo_name}
147→            parentBranch={workspace.git_target_branch}
148→            isFirstSession={true}
149→            initializing={workspace.state === "initializing"}
150→            initStep={workspace.init_stage}

