// Effect: when the pending workspace becomes ready with a session, send the queued message
useEffect(() => {
  const pending = pendingWelcomeMessageRef.current;
  if (!pending) return;
  if (!selectedWorkspace) return;
  if (selectedWorkspace.id !== pending.workspaceId) return;
  // Workspace must be ready with a session
  if (selectedWorkspace.state !== "ready" || !selectedWorkspace.current_session_id) return;
  if (!selectedWorkspace.workspace_path) return;

  // Clear the pending ref before sending to prevent double-fire
  const { message, model } = pending;
  pendingWelcomeMessageRef.current = null;

  const sessionId = selectedWorkspace.current_session_id;
  const cwd = selectedWorkspace.workspace_path;
  const runtimeModelId = getRuntimeModelId(model);
  const agentType = getRuntimeAgentTypeForModel(model);

  // Fire-and-forget: send the message via WS command
  (async () => {
    try {
      if (!isConnected()) await connect();
      const ack = await sendCommand("sendMessage", {
        sessionId,
        content: message,
        model: runtimeModelId,
        cwd,
        agentType,
      });
      if (!ack.accepted) {
        toast.error(ack.error || "Failed to send message");
      }
    } catch (error) {
      console.error("Failed to send welcome message:", error);
      toast.error(getErrorMessage(error));
    }
  })();
}, [selectedWorkspace]);

